import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
changes = [(k, b.get(k), a.get(k)) for k in set(list(b.keys()) + list(a.keys())) if b.get(k) != a.get(k)]
if changes:
    for c in changes: print(f'CHANGED: {c}')
else:
    print('All packages resolve to identical versions - conversion is version-neutral.')
"

